module top_module (
    input [2:0] i,
    output reg invalid_output
);

    always @(*) begin
        case (i)
            3'b000: invalid_output = 1;
            3'b001: invalid_output = 1;
            3'b010: invalid_output = 0;
            3'b011: invalid_output = 1;
            3'b100: invalid_output = 0;
            3'b101: invalid_output = 1;
            3'b110: invalid_output = 0;
            3'b111: invalid_output = 0;
            default: invalid_output = 0; // Default case
        endcase
    end
endmodule
